from dataclasses import dataclass
from typing import Literal

@dataclass
class WorkloadProfile:
    name: str
    data_class: Literal["public","internal","confidential","restricted","highly_restricted"]
    daily_tokens_M: float   # millions
    latency_requirement: Literal["interactive","batch"]
    needs_fine_tuning: bool
    has_mlops_team: bool

def recommend_model_category(w: WorkloadProfile) -> tuple[str, str]:
    """Return (category, rationale)."""
    if w.data_class == "highly_restricted":
        return "open-weight-self-hosted", "Data classification requires on-premise hosting"
    if not w.has_mlops_team:
        return "closed-proprietary", "No MLOps team to operate self-hosted serving"
    if w.latency_requirement == "interactive" and w.daily_tokens_M < 20:
        return "closed-proprietary", "Interactive latency SLA + low volume favours closed API"
    if w.daily_tokens_M >= 50:
        return "open-weight-self-hosted", "Volume economics favour self-hosting above 50M tokens/day"
    if w.needs_fine_tuning:
        return "open-weight-self-hosted", "Full weight access needed for custom fine-tuning"
    return "closed-proprietary", "Moderate volume, no special constraints"

profiles = [
    WorkloadProfile("HR document assistant", "restricted", 5, "interactive", False, True),
    WorkloadProfile("Log anomaly batch analyser", "internal", 200, "batch", True, True),
    WorkloadProfile("Air-gap ops planning", "highly_restricted", 3, "batch", False, True),
    WorkloadProfile("Customer chat agent", "confidential", 15, "interactive", False, False),
]

for p in profiles:
    cat, rationale = recommend_model_category(p)
    print(f"{p.name}: {cat} — {rationale}")
